        printf("Invalid number of elements. Please enter a number between 1 and 100.\n");
        return 1;
    }

    // Ask the user to enter the elements
    printf("Enter %d elements:\n", n);
    for (i = 0; i < n; i++) {
        printf("Element %d: ", i + 1);
        scanf("%d", &data[i]);
    }

    // Display the elements in a table format
    printf("\nTable of entered elements:\n");
    for (i = 0; i < n; i++) {
        printf("Element %d: %d\n", i + 1, data[i]);
    }

    return 0;
}
```

