In C++, you can start a new process and connect one file descriptor to its input and output using the `fork()` and `exec()` family of functions, along with file descriptor redirection. Here's a simple example:

```cpp
#include <iostream>
#include <unistd.h>
#include <sys/wait.h>
#include <stdio.h>

int main() {
    int pipefd[2];
    pid_t pid;

    // Create a pipe
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Fork a child process
    pid = fork();
    if (pid < 0) {  // Error occurred
        perror("fork");
        return 1;
    } else if (pid == 0) {  // Child process
        // Close unused write end of pipe
        close(pipefd[1]);

        // Redirection: file descriptor 0 (stdin) to read end of pipe
        dup2(pipefd[0], STDIN_FILENO);

        // Close the read end of the pipe since it's now a duplicate of stdin
        close(pipefd[0]);

        // Execute a new program
        execlp("cat", "cat", (char*)NULL);
        perror("execlp");
        _exit(1);  // Exit if execlp fails
    } else {  // Parent process
        // Close unused read end of pipe
        close(pipefd[0]);

        // Redirect the write end of the pipe to the child's stdout
        dup2(pipefd[1], STDOUT_FILENO);

        // Close the write end of the pipe since it's now a duplicate of stdout
        close(pipefd[1]);

        // Write something to the pipe
        std::cout << "Hello from parent process!" << std::endl;

        // Wait for the child process to finish
        wait(NULL);
    }

    return 0;
}
```

In this example, we create a pipe and fork a child process. The child process uses the read end of the pipe as its standard input, and the parent process uses the write end of the pipe as its standard output. The `cat` command is used in the child process to read from its standard input.
